// ─── DAY 2 & DAY 3 PROSPECTS (Ranks 51-250) ───────────────────────
// Sourced from DraftTek Top 600 Big Board (March 31, 2026)
// Grades scale: 72-74 (Rd 3), 68-72 (Rd 4), 64-68 (Rd 5), 60-64 (Rd 6-7)
function g(rank: number): number {
  if (rank <= 64) return 73;
  if (rank <= 100) return 70;
  if (rank <= 140) return 68;
  if (rank <= 180) return 65;
  if (rank <= 220) return 63;
  return 61;
}
function pr(rank: number): number {
  if (rank <= 64) return 3;
  if (rank <= 100) return 4;
  if (rank <= 140) return 4;
  if (rank <= 180) return 5;
  if (rank <= 220) return 6;
  return 7;
}

